def cavern_props_js():
    """JS snippet: decode + preload prop images once at shell init."""
    data = json.dumps(CAVERN_PROPS, separators=(",", ":"))
    return (
        '(function(){var D=' + data + ';'
        'window._cavernPropImgs={};var pending=0;'
        'function done(){if(--pending===0&&window._cavernRedrawAll)window._cavernRedrawAll();}'
        'for(var g in D){window._cavernPropImgs[g]=D[g].map(function(b){'
        'var im=new Image();pending++;im.onload=done;im.onerror=done;'
        'im.src="data:image/webp;base64,"+b;return im;});}'
        '})();'
    )
